#include <stdio.h>
#include <string.h>
#include <stdbool.h>

int main() {
    char s[27];
    scanf("%s", s);
    int n;
    scanf("%d", &n);

    for (int i = 0; i < n; i++) {
        char word[13];
        scanf("%s", word);
        bool canRead = true;

        for (int j = 0; j < strlen(word); j++) {
            bool found = false;
            for (int k = 0; k < strlen(s); k++) {
                if (word[j] == s[k]) {
                    found = true;
                    break;
                }
            }
            if (!found) {
                canRead = false;
                break;
            }
        }

        if (canRead) {
            printf("Yes\n");
        } else {
            printf("No\n");
        }
    }

    return 0;
}

